// Frigate event structure: {type, before, after}
let event = msg.payload;
if (!event || !event.after) { return null; }

let after = event.after;
msg.eventType  = event.type;          // 'new', 'update', 'end'
msg.label      = after.label;         // 'person', 'car'
msg.score      = after.top_score;
msg.camera     = after.camera;
msg.hasSnap    = after.has_snapshot;
msg.faceName   = after.sub_label || null; // face recognition result
msg.plate      = after.attributes && after.attributes.license_plate
                   ? after.attributes.license_plate : null;

// Only act on 'new' events to avoid duplicate triggers
if (msg.eventType !== 'new') { return null; }

return msg;

msg.payload = JSON.stringify({id:0, on:true, toggle_after:300});
msg.headers = {'Content-Type':'application/json'};
return msg;

// Add your authorized plates here
let whitelist = ['AB123CD', 'EF456GH', 'IJ789KL'];
let plate = msg.plate ? msg.plate.toUpperCase() : null;

if (!plate || whitelist.indexOf(plate) !== -1) {
  // No plate detected or plate is authorized
  return [msg, null];
} else {
  msg.unknownPlate = plate;
  return [null, msg];
}

// Requires node-red-contrib-telegrambot
// Configure your bot token and chat ID in the Telegram node
msg.payload = {
  chatId: 'YOUR_CHAT_ID',
  type: 'message',
  content: '🏠 Welcome home, ' + (msg.faceName || 'family') + '! Hallway light is on.'
};
return msg;

msg.payload = {
  chatId: 'YOUR_CHAT_ID',
  type: 'message',
  content: '🔔 Unknown visitor detected at ' + msg.camera + ' (score: ' + Math.round(msg.score * 100) + '%)'
};
return msg;

msg.payload = {
  chatId: 'YOUR_CHAT_ID',
  type: 'message',
  content: '🚗 Unknown plate detected: ' + msg.unknownPlate + ' — camera: ' + msg.camera
};
return msg;
